    let maxSum = 0;
    const n = nums.length;

    // Iterate all possible masks for B (subset of nums)
    for (let maskB = 0; maskB < (1 << n); maskB++) {
        let andB = ~0; // Initialize to all 1s (bitwise AND identity)
        let xorA = 0;
        let xorC = 0;

        for (let i = 0; i < n; i++) {
            if (maskB & (1 << i)) {
                andB &= nums[i];
            }
        }

        // Now, iterate all possible masks for A (subset of nums not in B)
        for (let maskA = 0; maskA < (1 << n); maskA++) {
            // Check if maskA and maskB are disjoint
            if ((maskA & maskB) !== 0) continue;

            xorA = 0;
            for (let i = 0; i < n; i++) {
                if (maskA & (1 << i)) {
                    xorA ^= nums[i];
                }
            }

            // C is the remaining elements (not in A or B)
            xorC = 0;
            for (let i = 0; i < n; i++) {
                if (!(maskA & (1 << i)) && !(maskB & (1 << i))) {
                    xorC ^= nums[i];
                }
            }

            const currentSum = xorA + andB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}

